const emb = items[0].json.embedding;
if (!emb || !Array.isArray(emb)) throw new Error('Ollama embedding missing — check OLLAMA_URL and model name');
const vecStr = '[' + emb.join(',') + ']';
const triggerInput = $('MCP Server Trigger').first().json.input;
return [{ json: {
  vec: vecStr,
  chat_id: triggerInput.chat_id || 0,
  query: triggerInput.query,
  top_k: triggerInput.top_k || 5
}}];

const chunks = items.map(it => ({
  doc_id: it.json.doc_id || it.json.chunk_id,
  section: it.json.section || '',
  text: it.json.text,
  score: parseFloat(it.json.score) || 0,
  source_uri: it.json.source_uri || ''
}));
return [{ json: { chunks, latency_ms: 0, mode: 'n8n' } }];

const docs = items.map(it => ({
  doc_id: it.json.doc_id,
  title: it.json.title,
  mime: it.json.mime,
  source: it.json.source,
  n_chunks: it.json.n_chunks,
  created_at: it.json.created_at
}));
return [{ json: { docs } }];
